mapper.select:
		/*
             SQL ID : AsmntCmntDAO.selectCmnt
             	설  명 : 과제 댓글 조회
         */

         AND R.ATCL_CMNT_ID = #{asmntCmntId}
         AND R.ASMT_ID = #{asmtId}
         AND R.STD_ID = #{stdNo}

		/*
             SQL ID : AsmntCmntDAO.listCmnt
             	설  명 : 과제 댓글 목록 조회
         */

           AND R.ASMT_ID = #{asmtId}
           AND R.STD_ID = #{stdNo}
         ORDER BY R.PATH

mapper.insert:
		/*
             SQL ID : AsmntCmntDAO.insertCmnt
             	설  명 : 과제 댓글 등록
         */
         INSERT INTO TB_LMS_ASMT_CMNT (
         	  ATCL_CMNT_ID
			, ASMT_ID
			, STD_ID
			, SBJCT_ID
			, UP_ATCL_CMNT_ID
			, ATCL_CMNT_CTS
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{asmntCmntId}
         	, #{asmtId}
         	, #{stdNo}
         	, #{crsCreCd}
         	, #{upAsmntCmntId}
         	, #{asmntCmntCts}
         	, 'N'
         	, #{userId}
         	, FN_DTTM()
         	, #{userId}
         	, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : AsmntCmntDAO.updateCmnt
             	설  명 : 과제 댓글 수정
         */
         UPDATE TB_LMS_ASMT_CMNT SET
         	  MDFR_ID = #{userId}
         	, MOD_DTTM = FN_DTTM()

         	, SBJCT_ID = #{crsCreCd}


         	, UP_ATCL_CMNT_ID = #{upAsmntCmntId}


         	, ATCL_CMNT_CTS = #{asmntCmntCts}


         	, DELYN = #{delYn}

          WHERE ATCL_CMNT_ID = #{asmntCmntId}
            AND ASMT_ID = #{asmtId}
            AND STD_ID = #{stdNo}
